import"./boot.js";function isPath(t){return 0<=t.indexOf(".")}function root(t){var n=t.indexOf(".");return-1===n?t:t.slice(0,n)}function isAncestor(t,n){return 0===t.indexOf(n+".")}function isDescendant(t,n){return 0===n.indexOf(t+".")}function translate(t,n,e){return n+e.slice(t.length)}function matches(t,n){return t===n||isAncestor(t,n)||isDescendant(t,n)}function normalize(e){if(Array.isArray(e)){let n=[];for(let t=0;t<e.length;t++){var r=e[t].toString().split(".");for(let t=0;t<r.length;t++)n.push(r[t])}return n.join(".")}return e}function split(t){return(Array.isArray(t)?normalize(t):t.toString()).split(".")}function get(t,n,e){let r=t,i=split(n);for(let t=0;t<i.length;t++){if(!r)return;var s=i[t];r=r[s]}return e&&(e.path=i.join(".")),r}function set(t,n,e){let r=t,i=split(n);t=i[i.length-1];if(1<i.length){for(let t=0;t<i.length-1;t++){var s=i[t];if(!(r=r[s]))return}r[t]=e}else r[n]=e;return i.join(".")}const isDeep=isPath;export{isPath,root,isAncestor,isDescendant,translate,matches,normalize,split,get,set,isDeep};